//! entity-reap — run our own `.lean` corpus (or any text) as queries against the
//! ~14M-title Wikipedia entity gazetteer and dump every matching entity, scored in
//! logits + Buleyean probabilities.
//!
//! Backends:
//!   * in-memory  : `--titles <dump>` (builds the gazetteer each run, ~24s)
//!   * disk knot  : `--knot <file.eknot>` (mmap'd, zero rebuild) — build it once with
//!                  `--build-knot <file.eknot> --titles <dump>`.
//!
//! Scanning fans out across files with `gnosis-frf`. The buleyean god formula
//! (in-crate) normalizes logits to probabilities — fully sovereign, no paid AI.
//!
//! Build (sovereign): pnpm run gnode -- run open-source/a0/src/monster-build.ts \
//!                       --gnosis-native-apps distributed-inference --bin entity-reap

use std::fs;
use std::io::Write;
use std::path::{Path, PathBuf};
use std::time::Instant;

use clap::Parser;
use distributed_inference::entity_gazetteer::{
    scan_entities, EntityLookup, Gazetteer, MappedGazetteer,
};
use gnosis_frf::prelude::{IntoParallelRefIterator, ParallelIterator};

#[derive(Parser, Debug)]
#[command(
    name = "entity-reap",
    about = "Tag .lean files with Wikipedia entities (logits)"
)]
struct Args {
    /// Newline-delimited Wikipedia title dump (for in-memory build or --build-knot).
    #[arg(long)]
    titles: Option<String>,
    /// Use a prebuilt mmap'd `.eknot` instead of building from --titles.
    #[arg(long)]
    knot: Option<String>,
    /// Build an `.eknot` from --titles, write it here, and exit.
    #[arg(long)]
    build_knot: Option<String>,
    /// Root directory to scan for `.lean` files.
    #[arg(long, default_value = "open-source/gnosis-math")]
    lean_root: String,
    /// Output JSONL path.
    #[arg(long, default_value = "/tmp/lean-entities.jsonl")]
    out: String,
    /// Max sliding-window length (tokens) for entity surface forms.
    #[arg(long, default_value_t = 5)]
    max_ngram: usize,
    /// Keep top-N entities per file.
    #[arg(long, default_value_t = 25)]
    top: usize,
    /// Optional cap on number of lean files (0 = all).
    #[arg(long, default_value_t = 0)]
    max_files: usize,
}

fn collect_lean(dir: &Path, acc: &mut Vec<PathBuf>) {
    let Ok(entries) = fs::read_dir(dir) else {
        return;
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path.is_dir() {
            let name = entry.file_name();
            let name = name.to_string_lossy();
            if name == ".git" || name == ".lake" || name == "lake-packages" {
                continue;
            }
            collect_lean(&path, acc);
        } else if path.extension().map(|e| e == "lean").unwrap_or(false) {
            acc.push(path);
        }
    }
}

fn json_str(s: &str) -> String {
    serde_json::to_string(s).unwrap_or_else(|_| "\"\"".to_string())
}

fn run_scan<L: EntityLookup + Sync>(lk: &L, args: &Args) {
    let mut files: Vec<PathBuf> = Vec::new();
    collect_lean(Path::new(&args.lean_root), &mut files);
    files.sort();
    if args.max_files > 0 && files.len() > args.max_files {
        files.truncate(args.max_files);
    }
    eprintln!("[entity-reap] scanning {} lean files…", files.len());

    let lean_root = args.lean_root.clone();
    let max_ngram = args.max_ngram;
    let top = args.top;

    let t1 = Instant::now();
    // (rel path, topic name, scored entities) per file; fan out with gnosis-frf.
    let results: Vec<(
        String,
        String,
        Vec<distributed_inference::entity_gazetteer::EntityHit>,
    )> = files
        .par_iter()
        .map(|path| {
            let content = fs::read_to_string(path).unwrap_or_default();
            let hits = scan_entities(lk, &content, max_ngram, top);
            let rel = path
                .strip_prefix(&lean_root)
                .unwrap_or(path)
                .to_string_lossy()
                .to_string();
            let name = path
                .file_stem()
                .map(|s| s.to_string_lossy().to_string())
                .unwrap_or_default();
            (rel, name, hits)
        })
        .collect();
    let scan_secs = t1.elapsed().as_secs_f64();

    let mut out = match fs::File::create(&args.out) {
        Ok(f) => std::io::BufWriter::new(f),
        Err(e) => {
            eprintln!("[entity-reap] cannot create {}: {e}", args.out);
            std::process::exit(1);
        }
    };

    let mut files_with_hits = 0usize;
    let mut total_links = 0usize;
    for (rel, name, hits) in &results {
        if !hits.is_empty() {
            files_with_hits += 1;
        }
        total_links += hits.len();
        let mut line = String::new();
        line.push_str("{\"lean\":");
        line.push_str(&json_str(rel));
        line.push_str(",\"topic\":");
        line.push_str(&json_str(name));
        line.push_str(",\"entities\":[");
        for (i, e) in hits.iter().enumerate() {
            if i > 0 {
                line.push(',');
            }
            line.push_str(&format!(
                "{{\"wiki\":{},\"url\":{},\"logit\":{},\"prob\":{:.6},\"span\":{},\"count\":{}}}",
                json_str(&e.slug),
                json_str(&format!("https://en.wikipedia.org/wiki/{}", e.slug)),
                e.logit,
                e.prob,
                e.span,
                e.count
            ));
        }
        line.push_str("]}\n");
        let _ = out.write_all(line.as_bytes());
    }
    let _ = out.flush();

    eprintln!(
        "[entity-reap] {} files, {} with >=1 entity, {} total entity links; scan {:.2}s ({:.0} files/s)",
        results.len(),
        files_with_hits,
        total_links,
        scan_secs,
        results.len() as f64 / scan_secs.max(1e-9)
    );
    eprintln!("[entity-reap] wrote {}", args.out);
}

fn build_in_memory(titles: &str, max_ngram: usize) -> Gazetteer {
    let t0 = Instant::now();
    eprintln!("[entity-reap] building gazetteer from {titles}");
    let gaz = match Gazetteer::build_from_file(Path::new(titles), max_ngram) {
        Ok(g) => g,
        Err(e) => {
            eprintln!("[entity-reap] failed to read titles: {e}");
            std::process::exit(1);
        }
    };
    eprintln!(
        "[entity-reap] gazetteer: {} entities in {:.1}s",
        gaz.entity_count(),
        t0.elapsed().as_secs_f64()
    );
    gaz
}

fn main() {
    let args = Args::parse();

    // Build-knot mode: build in memory, serialize to disk, exit.
    if let Some(knot_out) = &args.build_knot {
        let Some(titles) = &args.titles else {
            eprintln!("[entity-reap] --build-knot requires --titles");
            std::process::exit(1);
        };
        let gaz = build_in_memory(titles, args.max_ngram);
        let t = Instant::now();
        if let Err(e) = gaz.write_knot(Path::new(knot_out)) {
            eprintln!("[entity-reap] failed to write knot: {e}");
            std::process::exit(1);
        }
        let size = fs::metadata(knot_out).map(|m| m.len()).unwrap_or(0);
        eprintln!(
            "[entity-reap] wrote knot {} ({:.1} MB) in {:.1}s",
            knot_out,
            size as f64 / 1e6,
            t.elapsed().as_secs_f64()
        );
        return;
    }

    // Scan mode: prefer the mmap'd knot; otherwise build in memory.
    if let Some(knot) = &args.knot {
        let t = Instant::now();
        let mg = match MappedGazetteer::open(Path::new(knot)) {
            Ok(m) => m,
            Err(e) => {
                eprintln!("[entity-reap] failed to open knot {knot}: {e}");
                std::process::exit(1);
            }
        };
        eprintln!(
            "[entity-reap] mmap'd knot: {} entities in {:.3}s",
            mg.entity_count(),
            t.elapsed().as_secs_f64()
        );
        run_scan(&mg, &args);
    } else if let Some(titles) = &args.titles {
        let gaz = build_in_memory(titles, args.max_ngram);
        run_scan(&gaz, &args);
    } else {
        eprintln!("[entity-reap] need one of --titles, --knot, or --build-knot");
        std::process::exit(1);
    }
}
